static void CallStoredProcedureExample(Args _args)
{
    Connection          connection;
    Statement           statement;
    ResultSet           resultSet;
    SqlStatementExecutePermission permission;
    str                 sqlStmt;
    str                 procName;
    str                 paramValue1;
    int                 paramValue2;
    str                 resultColumn1;
    int                 resultColumn2;
    real                resultColumn3;
    ;

    // Initialize parameters for the stored procedure
    procName = 'sp_GetInventoryData';  // Replace with your stored procedure name
    paramValue1 = 'ITEM001';           // Replace with your parameter values
    paramValue2 = 100;

    try
    {
        // Create database connection
        connection = new Connection();

        if (!connection)
        {
            throw error("Failed to create database connection");
        }

        // Create statement object from connection
        statement = connection.createStatement();

        if (!statement)
        {
            throw error("Failed to create SQL statement");
        }

        // Build the SQL statement to call the stored procedure
        // Using SQL Server format - adjust for your database system
        sqlStmt = strfmt("EXEC %1 @ItemId = '%2', @Quantity = %3", 
                        procName, paramValue1, paramValue2);

        // Set up security permission for SQL execution
        permission = new SqlStatementExecutePermission(sqlStmt);
        permission.assert();

        // Execute the stored procedure and get results
        resultSet = statement.executeQuery(sqlStmt);

        // Revert permission immediately after execution
        CodeAccessPermission::revertAssert();

        if (!resultSet)
        {
            throw error("Failed to execute stored procedure");
        }

        // Process the result set
        while (resultSet.next())
        {
            // Get values from result columns (1-based indexing)
            resultColumn1 = resultSet.getString(1);    // First column as string
            resultColumn2 = resultSet.getInt(2);       // Second column as integer
            resultColumn3 = resultSet.getReal(3);      // Third column as real

            // Process the retrieved data
            info(strfmt("Row data: %1, %2, %3", 
                       resultColumn1, resultColumn2, num2str(resultColumn3, 0, 2, 1, 1)));
        }

        info("Stored procedure executed successfully");
    }
    catch (Exception::Error)
    {
        error("Failed to execute stored procedure: " + sqlStmt);
    }
    catch (Exception::Break)
    {
        warning("Operation cancelled by user");
    }

    // No explicit cleanup needed - AX manages Connection/Statement/ResultSet lifecycle
}

// Alternative method for stored procedures that return a single value
static str CallStoredProcedureScalar(str _procedureName, str _parameter)
{
    Connection          connection;
    Statement           statement;
    ResultSet           resultSet;
    SqlStatementExecutePermission permission;
    str                 sqlStmt;
    str                 result = "";
    ;

    try
    {
        connection = new Connection();
        statement = connection.createStatement();

        // Build SQL statement with parameter - escape single quotes
        sqlStmt = strfmt("EXEC %1 '%2'", _procedureName, strReplace(_parameter, "'", "''"));

        permission = new SqlStatementExecutePermission(sqlStmt);
        permission.assert();

        resultSet = statement.executeQuery(sqlStmt);

        CodeAccessPermission::revertAssert();

        // Get first row, first column only
        if (resultSet && resultSet.next())
        {
            result = resultSet.getString(1);
        }
    }
    catch (Exception::Error)
    {
        error(strfmt("Error calling stored procedure %1", _procedureName));
        result = "";
    }

    return result;
}

// Method to execute stored procedure with output parameters
static container CallStoredProcedureWithOutput(str _itemId)
{
    Connection          connection;
    Statement           statement;
    ResultSet           resultSet;
    SqlStatementExecutePermission permission;
    str                 sqlStmt;
    container           result;
    str                 itemName;
    real                onHand;
    real                available;
    ;

    result = conNull();

    try
    {
        connection = new Connection();
        statement = connection.createStatement();

        // For output parameters, typically need to use a SELECT statement after EXEC
        // This example shows a common pattern for SQL Server
        sqlStmt = strfmt(@"
            DECLARE @ItemName nvarchar(60), @OnHand decimal(28,12), @Available decimal(28,12)
            EXEC sp_GetItemAvailability '%1', @ItemName OUTPUT, @OnHand OUTPUT, @Available OUTPUT
            SELECT @ItemName, @OnHand, @Available", strReplace(_itemId, "'", "''"));

        permission = new SqlStatementExecutePermission(sqlStmt);
        permission.assert();

        resultSet = statement.executeQuery(sqlStmt);

        CodeAccessPermission::revertAssert();

        if (resultSet && resultSet.next())
        {
            itemName = resultSet.getString(1);
            onHand = resultSet.getReal(2);
            available = resultSet.getReal(3);

            result = [itemName, onHand, available];
        }
    }
    catch (Exception::Error)
    {
        error("Error executing stored procedure with output parameters");
        result = conNull();
    }

    return result;
}

// Method for stored procedures that perform updates (no result set)
static boolean ExecuteStoredProcedureUpdate(str _procedureName, container _parameters)
{
    Connection          connection;
    Statement           statement;
    SqlStatementExecutePermission permission;
    str                 sqlStmt;
    boolean             success = false;
    int                 i;
    str                 paramList;
    int                 rowsAffected;
    ;

    // Build parameter list from container
    for (i = 1; i <= conLen(_parameters); i++)
    {
        if (i > 1)
            paramList += ", ";

        // Handle different parameter types
        switch (typeof(conPeek(_parameters, i)))
        {
            case Types::String:
                // Escape single quotes for SQL safety
                paramList += strfmt("'%1'", strReplace(conPeek(_parameters, i), "'", "''"));
                break;
            case Types::Integer:
                paramList += int2str(conPeek(_parameters, i));
                break;
            case Types::Real:
                paramList += num2str(conPeek(_parameters, i), 0, 2, 1, 1);
                break;
            case Types::Date:
                paramList += strfmt("'%1'", date2str(conPeek(_parameters, i), 321, 
                                    DateDay::Digits2, DateSeparator::Hyphen, 
                                    DateMonth::Digits2, DateSeparator::Hyphen, 
                                    DateYear::Digits4));
                break;
            default:
                paramList += strfmt("'%1'", any2str(conPeek(_parameters, i)));
        }
    }

    try
    {
        connection = new Connection();
        statement = connection.createStatement();

        // Build SQL statement
        sqlStmt = strfmt("EXEC %1 %2", _procedureName, paramList);

        // Set up security permission
        permission = new SqlStatementExecutePermission(sqlStmt);
        permission.assert();

        // Execute the stored procedure (for non-query operations)
        rowsAffected = statement.executeUpdate(sqlStmt);

        CodeAccessPermission::revertAssert();

        success = true;

        info(strfmt("Stored procedure %1 executed. Rows affected: %2", _procedureName, rowsAffected));
    }
    catch (Exception::Error)
    {
        error(strfmt("Failed to execute stored procedure %1", _procedureName));
        success = false;
    }

    return success;
}
